

import React from 'react'
import { useSelector } from 'react-redux'
import { selectObserveCmpt } from '../../store/qvamarketsSlice';
import { CloseModal, getComponentStore } from '../../actions/common'



const DialogHRM = () => {
  
  const list = getComponentStore()['listDialog'] || {};
  const observeComponent=  useSelector(selectObserveCmpt);
  var _list = Object.keys(list);  
  const close = (Id) => {
    CloseModal({id:Id});
  }

  return (
            <>       
            {
              _list.map((dg,indg)=>{               
                var dlg = list[dg];
                if(dlg && dlg.visible){
                  var _Style={}
                  //var _cldg = cleanbase64(dg);
                  //_Style[`--s__${_cldg}_zIndex__`]=250;
                  //_Style[`--overlay__${_cldg}_zIndex__`]=249;   
                  if(dlg.height){
                    //_Style[`--s__${_cldg}_heigth__`]=dlg.height;
                  }
                  if(dlg.width){
                    //_Style[`--s__${_cldg}_width__`]=dlg.width; 
                  }
                  if(dlg.zIndex){
                    //_Style[`--s__${_cldg}_zIndex__`]=dlg.zIndex;
                    //_Style[`--overlay__${_cldg}_zIndex__`]=dlg.zIndex-1;
                    _Style["zIndex"] = dlg.zIndex-1;
                  }
                  var ts = {
                    // height: dlg.height,
                    // width: dlg.width,
                    zIndex: dlg.zIndex
                  };
                  let cmp2render = null;
                  let data = dlg.data
                  if(dlg.content){
                    cmp2render = React.cloneElement(dlg.content, {data});
                  }
                  return (
                      <div className={"ltr-1kbnjow"} style={_Style} key={dg} >
                        <div className={"ltr-hoe9xz"} >
                          <div className="ltr-1wao6ny" style={ts} id={dg}>
                            {cmp2render?cmp2render:null}
                          </div>
                        </div>
                        {dlg.data.overlay?<div className={`DialogHRMOverlay ${dlg.visible?"active":""}`} onClick={()=>close(dg)}/> :null}      
                      </div>
                    ) 
                }
              })
            }</>
        )
}

export default DialogHRM;



const cleanbase64 = id => {
  var cClss = id;
  var h = new RegExp('=','g')
  cClss=cClss.replace(h,'');
  return cClss;
};






